import * as React from "react";
import { MessageCardProps, MessageItem } from "../types";

/**
 * Componente MessageCard da aplicação
 * Exibe um item/mensagem individual com suporte a seleção
 * 
 * @param item - Item/mensagem a ser exibido
 * @param selectedIds - Array com IDs dos itens selecionados
 * @param setSelectedIds - Função para atualizar a seleção de itens
 */
const MessageCard = ({ item, selectedIds, setSelectedIds }: MessageCardProps) => {
  // Verifica se o item atual está selecionado
  const isSelected = selectedIds.includes(item.id);

  /**
   * Função para alternar a seleção do item
   * Adiciona ou remove o item da lista de selecionados
   */
  const toggleSelection = () => {
    setSelectedIds((prev: number[]) => 
      prev.includes(item.id)
        ? prev.filter((id: number) => id !== item.id)
        : [...prev, item.id]
    );
  };

  return (
    <div
      onClick={toggleSelection}
      className={`border rounded-lg p-4 cursor-pointer transition-all duration-200 ${
        isSelected
          ? "border-blue-500 bg-blue-50 shadow-md"
          : "border-gray-200 bg-white hover:border-gray-300 hover:shadow-sm"
      }`}
    >
      {/* Checkbox de seleção */}
      <div className="flex items-start gap-3">
        <div className="pt-1">
          <input
            type="checkbox"
            checked={isSelected}
            onChange={() => {}} // Controlado pelo onClick do container
            className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
            onClick={(e: any) => e.stopPropagation()} // Previne duplo clique
          />
        </div>
        
        {/* Conteúdo do item */}
        <div className="flex-1 min-w-0">
          {/* Nome do remetente/usuário */}
          <h3 className="text-lg font-medium text-gray-900 truncate">
            {item.name}
          </h3>
          
          {/* Assunto da mensagem */}
          <p className="text-sm text-gray-600 mt-1 line-clamp-2">
            {item.subject}
          </p>
          
          {/* Informações adicionais */}
          <div className="flex items-center gap-4 mt-2 text-xs text-gray-500">
            {/* Data da mensagem */}
            {item.date && (
              <span>{item.date}</span>
            )}
            
            {/* Número de usuários associados */}
            {item.users && item.users.length > 0 && (
              <span>{item.users.length} participante(s)</span>
            )}
            
            {/* Indicador de mensagem lida/não lida */}
            {item.read !== undefined && (
              <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                item.read
                  ? "bg-green-100 text-green-800"
                  : "bg-yellow-100 text-yellow-800"
              }`}>
                {item.read ? "Lida" : "Não lida"}
              </span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default MessageCard;
